{
  "name": "Sistem Monitoring Kapal Laonti-Kendari",
  "description": "Aplikasi monitoring status operasional kapal penyeberangan rute Pesisir Laonti–Kendari dengan Smart ETA dan timeline checkpoint desa untuk penumpang, kapten, dan admin.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ShipStatus {
  OPERATING = 'BEROPERASI',
  CANCELLED = 'TIDAK BEROPERASI',
  DELAYED = 'TERTUNDA'
}

export enum WeatherStatus {
  SUNNY = 'Cerah',
  RAIN = 'Hujan',
  ROUGH_WAVES = 'Berombak Besar'
}

export enum LoadStatus {
  AVAILABLE = 'Muatan Masih Tersedia',
  FULL = 'PENUH'
}

export interface Checkpoint {
  id: string;
  name: string;
  order: number;
}

export interface RouteSegment {
  fromId: string;
  toId: string;
  distanceKm: number;
  standardTimeMinutes: number;
}

export interface AppState {
  currentStatus: ShipStatus;
  currentCheckpointId: string; // The village ID where the ship is currently
  currentWeather: WeatherStatus;
  currentLoad: LoadStatus;
  delayReason: string;
  delayMinutes: number;
  announcement: string;
  shipName: string;
  departureTime: string;
}

export type UserRole = 'PUBLIC' | 'CAPTAIN' | 'ADMIN';

export interface ActivityLog {
  id: string;
  timestamp: string;
  action: string;
  user: string;
}

import { Checkpoint, RouteSegment, ShipStatus, WeatherStatus, LoadStatus } from './types';

export const CHECKPOINTS: Checkpoint[] = [
  { id: 'v1', name: 'Wandaeha', order: 0 },
  { id: 'v2', name: 'Woru-Woru', order: 1 },
  { id: 'v3', name: 'Tambeanga', order: 2 },
  { id: 'v4', name: 'Labotaone', order: 3 },
  { id: 'v5', name: 'Kendari', order: 4 },
];

export const ROUTE_SEGMENTS: RouteSegment[] = [
  { fromId: 'v1', toId: 'v2', distanceKm: 8, standardTimeMinutes: 30 },
  { fromId: 'v2', toId: 'v3', distanceKm: 12, standardTimeMinutes: 45 },
  { fromId: 'v3', toId: 'v4', distanceKm: 10, standardTimeMinutes: 35 },
  { fromId: 'v4', toId: 'v5', distanceKm: 15, standardTimeMinutes: 60 },
];

export const INITIAL_APP_STATE = {
  currentStatus: ShipStatus.OPERATING,
  currentCheckpointId: 'v1',
  currentWeather: WeatherStatus.SUNNY,
  currentLoad: LoadStatus.AVAILABLE,
  delayReason: '',
  delayMinutes: 0,
  announcement: 'Info: Kapal hari ini berangkat tepat waktu. Harap penumpang datang 30 menit sebelum keberangkatan.',
  shipName: 'KMP Bahtera Pesisir',
  departureTime: '08:00 WITA',
};

import React, { useState, useEffect } from 'react';
import { 
  Ship, 
  User, 
  Settings, 
  MapPin, 
  Clock, 
  CloudSun, 
  AlertCircle, 
  Anchor,
  LogOut,
  Bell,
  CheckCircle2,
  ChevronRight,
  Info
} from 'lucide-react';
import { 
  ShipStatus, 
  WeatherStatus, 
  LoadStatus, 
  UserRole, 
  AppState,
  ActivityLog 
} from './types';
import { 
  CHECKPOINTS, 
  ROUTE_SEGMENTS, 
  INITIAL_APP_STATE 
} from './constants';

// --- Shared Components ---

const RunningText: React.FC<{ text: string }> = ({ text }) => (
  <div className="bg-blue-600 text-white py-2 overflow-hidden whitespace-nowrap sticky top-0 z-50 shadow-md">
    <div className="inline-block animate-scroll font-medium">
      {text} • {text} • {text}
    </div>
  </div>
);

const Navbar: React.FC<{ role: UserRole; setRole: (role: UserRole) => void }> = ({ role, setRole }) => (
  <nav className="bg-white border-b px-4 py-3 flex justify-between items-center sticky top-[40px] z-40">
    <div className="flex items-center gap-2">
      <div className="bg-blue-600 p-2 rounded-lg">
        <Ship className="text-white w-5 h-5" />
      </div>
      <span className="font-bold text-slate-800 text-sm md:text-base">LAONTI-KENDARI TRACKER</span>
    </div>
    <div className="flex gap-2">
      <button 
        onClick={() => setRole('PUBLIC')}
        className={`p-2 rounded-full transition ${role === 'PUBLIC' ? 'bg-blue-100 text-blue-700' : 'text-slate-500 hover:bg-slate-100'}`}
        title="Publik"
      >
        <User className="w-5 h-5" />
      </button>
      <button 
        onClick={() => setRole('CAPTAIN')}
        className={`p-2 rounded-full transition ${role === 'CAPTAIN' ? 'bg-orange-100 text-orange-700' : 'text-slate-500 hover:bg-slate-100'}`}
        title="Kapten"
      >
        <Anchor className="w-5 h-5" />
      </button>
      <button 
        onClick={() => setRole('ADMIN')}
        className={`p-2 rounded-full transition ${role === 'ADMIN' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-100'}`}
        title="Admin"
      >
        <Settings className="w-5 h-5" />
      </button>
    </div>
  </nav>
);

// --- Public View Components ---

const StatusIndicator: React.FC<{ status: ShipStatus; load: LoadStatus }> = ({ status, load }) => {
  const getColor = () => {
    switch (status) {
      case ShipStatus.OPERATING: return 'bg-green-500';
      case ShipStatus.DELAYED: return 'bg-yellow-500';
      case ShipStatus.CANCELLED: return 'bg-red-500';
    }
  };

  return (
    <div className={`${getColor()} p-6 rounded-2xl shadow-lg text-white mb-6 transition-all transform hover:scale-[1.01]`}>
      <div className="flex justify-between items-start">
        <div>
          <p className="text-sm font-medium opacity-90 uppercase tracking-wider mb-1">Status Operasi</p>
          <h2 className="text-3xl font-black mb-4">{status}</h2>
        </div>
        <div className="bg-white/20 p-3 rounded-xl backdrop-blur-md">
          <Ship className="w-10 h-10" />
        </div>
      </div>
      <div className="flex items-center gap-2 bg-black/10 w-fit px-4 py-2 rounded-full mt-2">
        <CheckCircle2 className="w-4 h-4" />
        <span className="text-sm font-semibold">{load}</span>
      </div>
    </div>
  );
};

const SmartETACard: React.FC<{ 
  appState: AppState; 
  targetId: string; 
  setTargetId: (id: string) => void 
}> = ({ appState, targetId, setTargetId }) => {
  const targetCheckpoint = CHECKPOINTS.find(c => c.id === targetId);
  const currentCheckpoint = CHECKPOINTS.find(c => c.id === appState.currentCheckpointId);

  // Calculate ETA Logic
  const calculateETA = () => {
    if (!currentCheckpoint || !targetCheckpoint) return "N/A";
    if (currentCheckpoint.order >= targetCheckpoint.order) return "Sudah Tiba";

    let totalMinutes = 0;
    for (let i = currentCheckpoint.order; i < targetCheckpoint.order; i++) {
      const segment = ROUTE_SEGMENTS.find(s => s.fromId === CHECKPOINTS[i].id && s.toId === CHECKPOINTS[i+1].id);
      if (segment) totalMinutes += segment.standardTimeMinutes;
    }

    // Weather multiplier
    let weatherFactor = 1.0;
    if (appState.currentWeather === WeatherStatus.RAIN) weatherFactor = 1.2;
    if (appState.currentWeather === WeatherStatus.ROUGH_WAVES) weatherFactor = 1.5;

    totalMinutes = (totalMinutes * weatherFactor) + appState.delayMinutes;

    const now = new Date();
    now.setMinutes(now.getMinutes() + totalMinutes);
    return now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' }) + " WITA";
  };

  return (
    <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm mb-6">
      <div className="flex items-center gap-2 mb-4">
        <div className="bg-blue-100 p-2 rounded-lg text-blue-600">
          <Clock className="w-5 h-5" />
        </div>
        <h3 className="font-bold text-slate-800">Smart ETA (Estimasi Tiba)</h3>
      </div>

      <div className="space-y-4">
        <label className="block text-sm font-medium text-slate-600">Pilih Desa Tujuan:</label>
        <select 
          value={targetId}
          onChange={(e) => setTargetId(e.target.value)}
          className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none transition"
        >
          {CHECKPOINTS.map((cp, idx) => (
            <option key={cp.id} value={cp.id} disabled={cp.order <= (currentCheckpoint?.order || 0)}>
              {cp.name} {cp.order <= (currentCheckpoint?.order || 0) ? '(Telah Dilewati)' : ''}
            </option>
          ))}
        </select>

        <div className="bg-blue-50 p-4 rounded-xl border border-blue-100">
          <p className="text-xs text-blue-600 font-bold uppercase tracking-widest mb-1">Estimasi Tiba di {targetCheckpoint?.name}</p>
          <p className="text-2xl font-black text-blue-900">{calculateETA()}</p>
          <div className="mt-2 flex flex-wrap gap-2">
            <span className="text-[10px] bg-white text-slate-500 px-2 py-1 rounded border border-blue-100 flex items-center gap-1">
              <CloudSun className="w-3 h-3" /> {appState.currentWeather}
            </span>
            {appState.delayMinutes > 0 && (
              <span className="text-[10px] bg-yellow-100 text-yellow-700 px-2 py-1 rounded border border-yellow-200 font-bold">
                +{appState.delayMinutes}m Delay
              </span>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const RouteTimeline: React.FC<{ currentCheckpointId: string }> = ({ currentCheckpointId }) => {
  const currentIdx = CHECKPOINTS.findIndex(c => c.id === currentCheckpointId);

  return (
    <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm mb-6 overflow-hidden">
      <div className="flex items-center gap-2 mb-8">
        <div className="bg-indigo-100 p-2 rounded-lg text-indigo-600">
          <MapPin className="w-5 h-5" />
        </div>
        <h3 className="font-bold text-slate-800">Visualisasi Rute Checkpoint</h3>
      </div>

      <div className="relative flex flex-col gap-12">
        {/* Connection Line */}
        <div className="absolute left-[19px] top-4 bottom-4 w-1 bg-slate-100"></div>
        <div 
          className="absolute left-[19px] top-4 w-1 bg-blue-500 transition-all duration-1000"
          style={{ height: `${(currentIdx / (CHECKPOINTS.length - 1)) * 100}%` }}
        ></div>

        {CHECKPOINTS.map((checkpoint, idx) => {
          const isPassed = idx < currentIdx;
          const isCurrent = idx === currentIdx;
          const segmentToNext = ROUTE_SEGMENTS.find(s => s.fromId === checkpoint.id);

          return (
            <div key={checkpoint.id} className="relative z-10">
              <div className="flex items-center gap-4">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center border-4 transition-all duration-500 ${
                  isPassed ? 'bg-blue-500 border-blue-100 text-white' : 
                  isCurrent ? 'bg-white border-blue-500 text-blue-500 scale-125 shadow-lg' : 
                  'bg-white border-slate-200 text-slate-300'
                }`}>
                  {isPassed ? <CheckCircle2 className="w-5 h-5" /> : idx + 1}
                </div>
                <div>
                  <h4 className={`font-bold transition-all ${isCurrent ? 'text-blue-600 text-lg' : 'text-slate-700'}`}>
                    Desa {checkpoint.name}
                  </h4>
                  {isCurrent && <span className="text-[10px] bg-blue-100 text-blue-700 font-bold px-2 py-0.5 rounded uppercase">Posisi Kapal</span>}
                </div>
              </div>

              {/* Segment Info (Jarak & Waktu) */}
              {idx < CHECKPOINTS.length - 1 && segmentToNext && (
                <div className="ml-14 mt-4 mb-2 p-2 bg-slate-50 rounded-lg border border-dashed border-slate-200 flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <span className="text-xs font-medium text-slate-500">{segmentToNext.distanceKm} Km</span>
                    <ChevronRight className="w-3 h-3 text-slate-300" />
                    <span className="text-xs font-medium text-slate-500">±{segmentToNext.standardTimeMinutes} menit</span>
                  </div>
                  <div className="h-[2px] flex-1 mx-4 bg-slate-200"></div>
                  {isCurrent && <Ship className="w-4 h-4 text-blue-500 animate-bounce" />}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

// --- Captain Screen Components ---

const CaptainPanel: React.FC<{ 
  appState: AppState; 
  updateState: (partial: Partial<AppState>) => void;
  addLog: (action: string) => void;
}> = ({ appState, updateState, addLog }) => {
  return (
    <div className="p-4 max-w-lg mx-auto pb-24">
      <div className="bg-orange-600 p-6 rounded-2xl text-white mb-6 shadow-xl">
        <div className="flex items-center gap-3 mb-2">
          <Anchor className="w-6 h-6" />
          <h2 className="text-xl font-bold">Panel Kapten</h2>
        </div>
        <p className="opacity-80 text-sm">Operator: Kapt. Herman Syah • {appState.shipName}</p>
      </div>

      <div className="space-y-6">
        {/* Checkpoint Village */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <label className="block text-sm font-bold text-slate-700 mb-3">Update Posisi (Desa Terakhir):</label>
          <div className="grid grid-cols-1 gap-2">
            {CHECKPOINTS.map((cp) => (
              <button
                key={cp.id}
                onClick={() => {
                  updateState({ currentCheckpointId: cp.id });
                  addLog(`Update posisi ke Desa ${cp.name}`);
                }}
                className={`p-4 rounded-xl text-left border-2 transition font-semibold flex justify-between items-center ${
                  appState.currentCheckpointId === cp.id 
                    ? 'border-blue-500 bg-blue-50 text-blue-700' 
                    : 'border-slate-100 text-slate-500'
                }`}
              >
                {cp.name}
                {appState.currentCheckpointId === cp.id && <CheckCircle2 className="w-5 h-5" />}
              </button>
            ))}
          </div>
        </div>

        {/* Status Operasi */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <label className="block text-sm font-bold text-slate-700 mb-3">Update Status Operasi:</label>
          <div className="flex gap-2">
            {[ShipStatus.OPERATING, ShipStatus.DELAYED, ShipStatus.CANCELLED].map((st) => (
              <button
                key={st}
                onClick={() => {
                  updateState({ currentStatus: st });
                  addLog(`Update status ke ${st}`);
                }}
                className={`flex-1 p-3 rounded-xl text-xs font-bold transition border-2 ${
                  appState.currentStatus === st
                    ? st === ShipStatus.OPERATING ? 'bg-green-100 border-green-500 text-green-700' :
                      st === ShipStatus.DELAYED ? 'bg-yellow-100 border-yellow-500 text-yellow-700' :
                      'bg-red-100 border-red-500 text-red-700'
                    : 'bg-white border-slate-100 text-slate-400'
                }`}
              >
                {st}
              </button>
            ))}
          </div>
        </div>

        {/* Cuaca */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <label className="block text-sm font-bold text-slate-700 mb-3">Kondisi Cuaca:</label>
          <div className="grid grid-cols-3 gap-2">
            {[WeatherStatus.SUNNY, WeatherStatus.RAIN, WeatherStatus.ROUGH_WAVES].map((ws) => (
              <button
                key={ws}
                onClick={() => {
                  updateState({ currentWeather: ws });
                  addLog(`Update cuaca ke ${ws}`);
                }}
                className={`p-3 rounded-xl text-[10px] font-bold transition border-2 text-center flex flex-col items-center gap-1 ${
                  appState.currentWeather === ws 
                    ? 'border-blue-500 bg-blue-50 text-blue-700' 
                    : 'border-slate-100 text-slate-400'
                }`}
              >
                <CloudSun className="w-5 h-5" />
                {ws}
              </button>
            ))}
          </div>
        </div>

        {/* Load Status */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <label className="block text-sm font-bold text-slate-700 mb-3">Status Muatan:</label>
          <div className="grid grid-cols-2 gap-2">
            {[LoadStatus.AVAILABLE, LoadStatus.FULL].map((ls) => (
              <button
                key={ls}
                onClick={() => {
                  updateState({ currentLoad: ls });
                  addLog(`Update muatan ke ${ls}`);
                }}
                className={`p-3 rounded-xl text-xs font-bold transition border-2 text-center ${
                  appState.currentLoad === ls 
                    ? 'border-blue-500 bg-blue-50 text-blue-700' 
                    : 'border-slate-100 text-slate-400'
                }`}
              >
                {ls}
              </button>
            ))}
          </div>
        </div>

        {/* Delay Reason */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <label className="block text-sm font-bold text-slate-700 mb-3">Alasan Delay (Jika Ada):</label>
          <input 
            type="text"
            value={appState.delayReason}
            onChange={(e) => updateState({ delayReason: e.target.value })}
            placeholder="Contoh: Bongkar muat lama..."
            className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm"
          />
          <div className="mt-4">
             <label className="block text-xs font-medium text-slate-500 mb-1">Menit Tambahan:</label>
             <input 
              type="number"
              value={appState.delayMinutes}
              onChange={(e) => updateState({ delayMinutes: parseInt(e.target.value) || 0 })}
              className="w-24 bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm"
            />
          </div>
        </div>
      </div>
    </div>
  );
};

// --- Admin Panel Components ---

const AdminPanel: React.FC<{ 
  appState: AppState; 
  updateState: (partial: Partial<AppState>) => void;
  logs: ActivityLog[];
}> = ({ appState, updateState, logs }) => {
  return (
    <div className="p-4 max-w-4xl mx-auto pb-24">
      <div className="bg-slate-900 p-8 rounded-2xl text-white mb-8 flex justify-between items-center shadow-xl">
        <div>
          <h2 className="text-2xl font-black mb-1 tracking-tight">System Dashboard</h2>
          <p className="opacity-60 text-xs uppercase font-bold tracking-widest">Administrator Control Unit</p>
        </div>
        <Settings className="w-10 h-10 opacity-20" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Manage Announcement */}
        <div className="bg-white p-6 rounded-2xl border shadow-sm">
          <div className="flex items-center gap-2 mb-4">
            <Bell className="w-5 h-5 text-indigo-600" />
            <h3 className="font-bold">Kelola Pengumuman</h3>
          </div>
          <textarea 
            value={appState.announcement}
            onChange={(e) => updateState({ announcement: e.target.value })}
            className="w-full h-32 bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            placeholder="Tulis pengumuman di sini..."
          />
          <button className="mt-3 w-full bg-indigo-600 text-white font-bold py-3 rounded-xl hover:bg-indigo-700 transition">Update Running Text</button>
        </div>

        {/* Manage Master Data Info */}
        <div className="bg-white p-6 rounded-2xl border shadow-sm">
          <div className="flex items-center gap-2 mb-4">
            <Info className="w-5 h-5 text-blue-600" />
            <h3 className="font-bold">Data Master Desa & Rute</h3>
          </div>
          <div className="space-y-3">
            {ROUTE_SEGMENTS.map((seg, idx) => (
              <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-100">
                <span className="text-xs font-bold text-slate-700">{CHECKPOINTS.find(c => c.id === seg.fromId)?.name} → {CHECKPOINTS.find(c => c.id === seg.toId)?.name}</span>
                <div className="flex gap-2">
                  <span className="text-[10px] bg-white px-2 py-1 rounded border">{seg.distanceKm}Km</span>
                  <span className="text-[10px] bg-white px-2 py-1 rounded border">{seg.standardTimeMinutes}m</span>
                </div>
              </div>
            ))}
          </div>
          <p className="mt-4 text-[10px] text-slate-400 italic font-medium">*Parameter ini digunakan untuk perhitungan Smart ETA otomatis.</p>
        </div>

        {/* Log Aktivitas */}
        <div className="bg-white p-6 rounded-2xl border shadow-sm md:col-span-2">
          <div className="flex items-center gap-2 mb-4">
            <Clock className="w-5 h-5 text-slate-500" />
            <h3 className="font-bold">Log Aktivitas Terbaru</h3>
          </div>
          <div className="space-y-2 max-h-64 overflow-y-auto pr-2">
            {logs.length === 0 && <p className="text-slate-400 text-sm text-center py-4">Belum ada aktivitas.</p>}
            {logs.slice().reverse().map((log) => (
              <div key={log.id} className="flex justify-between items-center p-3 hover:bg-slate-50 rounded-lg border-b border-slate-100 last:border-0">
                <div>
                  <p className="text-sm font-semibold text-slate-800">{log.action}</p>
                  <p className="text-[10px] text-slate-400">{log.user}</p>
                </div>
                <span className="text-[10px] font-mono text-slate-500">{log.timestamp}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

// --- Main App Entry ---

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>('PUBLIC');
  const [appState, setAppState] = useState<AppState>(INITIAL_APP_STATE);
  const [targetId, setTargetId] = useState<string>('v5');
  const [logs, setLogs] = useState<ActivityLog[]>([]);

  const updateState = (partial: Partial<AppState>) => {
    setAppState(prev => ({ ...prev, ...partial }));
  };

  const addLog = (action: string) => {
    const newLog: ActivityLog = {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString('id-ID'),
      action,
      user: role === 'CAPTAIN' ? 'Kapt. Herman' : 'Superadmin'
    };
    setLogs(prev => [...prev, newLog]);
  };

  // Ensure targetId is always valid (not passed or current)
  useEffect(() => {
    const currentCp = CHECKPOINTS.find(c => c.id === appState.currentCheckpointId);
    const targetCp = CHECKPOINTS.find(c => c.id === targetId);
    if (currentCp && targetCp && targetCp.order <= currentCp.order) {
      // Find next possible village
      const nextAvailable = CHECKPOINTS.find(c => c.order > currentCp.order);
      if (nextAvailable) setTargetId(nextAvailable.id);
    }
  }, [appState.currentCheckpointId, targetId]);

  return (
    <div className="min-h-screen pb-20 bg-slate-50">
      <RunningText text={appState.announcement} />
      <Navbar role={role} setRole={setRole} />

      <main className="container mx-auto px-4 py-6">
        {role === 'PUBLIC' && (
          <div className="max-w-2xl mx-auto space-y-6">
            <StatusIndicator status={appState.currentStatus} load={appState.currentLoad} />

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <SmartETACard appState={appState} targetId={targetId} setTargetId={setTargetId} />

              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-center">
                <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
