const StatusIndicator: React.FC<{ appState: AppState }> = ({ appState }) => {
  const getColor = () => {
    if (appState.tripPhase === TripPhase.COMPLETED) return 'bg-slate-700';
    switch (appState.currentStatus) {
      case ShipStatus.OPERATING: return 'bg-green-500';
      case ShipStatus.DELAYED: return 'bg-yellow-500';
      case ShipStatus.CANCELLED: return 'bg-red-500';
    }
  };

  const getSubStatusText = () => {
    if (appState.tripPhase === TripPhase.NOT_STARTED) return "Menunggu Keberangkatan";
    if (appState.tripPhase === TripPhase.COMPLETED) return "Tiba di Kendari (Selesai)";

    const nextCp = CHECKPOINTS.find(c => c.id === appState.nextCheckpointId);
    const currCp = CHECKPOINTS.find(c => c.id === appState.currentCheckpointId);

    if (appState.tripPhase === TripPhase.IN_TRANSIT) {
      return `Sedang Menuju ${nextCp?.name || 'Tujuan'}`;
    }
    if (appState.tripPhase === TripPhase.DOCKING) {
      return `Tiba di ${currCp?.name || 'Checkpoint'}`;
    }
    return appState.currentStatus;
  };

  return (
    <div className={`${getColor()} p-6 rounded-2xl shadow-lg text-white mb-6 transition-all transform hover:scale-[1.01]`}>
      <div className="flex justify-between items-start">
        <div>
          <p className="text-sm font-medium opacity-90 uppercase tracking-wider mb-1">
            Status Perjalanan
          </p>
          <h2 className="text-3xl font-black mb-1">{appState.currentStatus}</h2>
          <p className="text-lg font-bold opacity-90 flex items-center gap-2">
            <Navigation className="w-5 h-5" /> {getSubStatusText()}
          </p>
        </div>
        <div className="bg-white/20 p-3 rounded-xl backdrop-blur-md">
          <Ship className={`w-10 h-10 ${appState.tripPhase === TripPhase.IN_TRANSIT ? 'animate-pulse' : ''}`} />
        </div>
      </div>
      <div className="flex items-center gap-2 bg-black/10 w-fit px-4 py-2 rounded-full mt-6">
        <CheckCircle2 className="w-4 h-4" />
        <span className="text-sm font-semibold">{appState.currentLoad}</span>
      </div>
    </div>
  );
};

const SmartETACard: React.FC<{ 
  appState: AppState; 
  targetId: string; 
  setTargetId: (id: string) => void 
}> = ({ appState, targetId, setTargetId }) => {
  const targetCheckpoint = CHECKPOINTS.find(c => c.id === targetId);
  const currentIdx = CHECKPOINTS.findIndex(c => c.id === appState.currentCheckpointId);

  const calculateETA = () => {
    if (appState.tripPhase === TripPhase.NOT_STARTED) return "Belum Berangkat";
    if (appState.tripPhase === TripPhase.COMPLETED) return "Tiba di Kendari";
    if (!targetCheckpoint) return "N/A";

    const targetIdx = targetCheckpoint.order;
    if (currentIdx >= targetIdx) return "Sudah Tiba";

    let totalMinutes = 0;
    // Start from current position
    // If we are at v1, we need segment v1->v2, v2->v3...
    // If we are NOT_STARTED, logic starts when 'Berangkat' is clicked.
    for (let i = Math.max(0, currentIdx); i < targetIdx; i++) {
      const segment = ROUTE_SEGMENTS.find(s => s.fromId === CHECKPOINTS[i].id && s.toId === CHECKPOINTS[i+1].id);
      if (segment) totalMinutes += segment.standardTimeMinutes;
    }

    // Weather multiplier
    let weatherFactor = 1.0;
    if (appState.currentWeather === WeatherStatus.RAIN) weatherFactor = 1.2;
    if (appState.currentWeather === WeatherStatus.ROUGH_WAVES) weatherFactor = 1.5;

    totalMinutes = (totalMinutes * weatherFactor) + appState.delayMinutes;

    const now = new Date();
    now.setMinutes(now.getMinutes() + totalMinutes);
    return now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' }) + " WITA";
  };

  return (
    <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm mb-6">
      <div className="flex items-center gap-2 mb-4">
        <div className="bg-blue-100 p-2 rounded-lg text-blue-600">
          <Clock className="w-5 h-5" />
        </div>
        <h3 className="font-bold text-slate-800">Smart ETA (Estimasi Tiba)</h3>
      </div>

      <div className="space-y-4">
        <label className="block text-sm font-medium text-slate-600">Pilih Desa Tujuan:</label>
        <select 
          value={targetId}
          onChange={(e) => setTargetId(e.target.value)}
          className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none transition"
        >
          {CHECKPOINTS.map((cp) => (
            <option key={cp.id} value={cp.id} disabled={cp.order <= currentIdx}>
              {cp.name} {cp.order <= currentIdx ? '(Telah Dilewati)' : ''}
            </option>
          ))}
        </select>

        <div className="bg-blue-50 p-4 rounded-xl border border-blue-100">
          <p className="text-xs text-blue-600 font-bold uppercase tracking-widest mb-1">Estimasi Tiba di {targetCheckpoint?.name}</p>
          <p className="text-2xl font-black text-blue-900">{calculateETA()}</p>
          <div className="mt-2 flex flex-wrap gap-2">
            <span className="text-[10px] bg-white text-slate-500 px-2 py-1 rounded border border-blue-100 flex items-center gap-1">
              <CloudSun className="w-3 h-3" /> {appState.currentWeather}
            </span>
            {appState.delayMinutes > 0 && (
              <span className="text-[10px] bg-yellow-100 text-yellow-700 px-2 py-1 rounded border border-yellow-200 font-bold">
                +{appState.delayMinutes}m Delay
              </span>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const RouteTimeline: React.FC<{ appState: AppState }> = ({ appState }) => {
  const currentIdx = CHECKPOINTS.findIndex(c => c.id === appState.currentCheckpointId);
  const nextIdx = CHECKPOINTS.findIndex(c => c.id === appState.nextCheckpointId);

  return (
    <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm mb-6 overflow-hidden">
      <div className="flex items-center gap-2 mb-8">
        <div className="bg-indigo-100 p-2 rounded-lg text-indigo-600">
          <MapPin className="w-5 h-5" />
        </div>
        <h3 className="font-bold text-slate-800">Visualisasi Rute Checkpoint</h3>
      </div>

      <div className="relative flex flex-col gap-12">
        <div className="absolute left-[19px] top-4 bottom-4 w-1 bg-slate-100"></div>
        <div 
          className="absolute left-[19px] top-4 w-1 bg-blue-500 transition-all duration-1000"
          style={{ height: `${currentIdx >= 0 ? (currentIdx / (CHECKPOINTS.length - 1)) * 100 : 0}%` }}
        ></div>

        {CHECKPOINTS.map((checkpoint, idx) => {
          const isPassed = idx <= currentIdx;
          const isHeadingTo = idx === nextIdx && appState.tripPhase === TripPhase.IN_TRANSIT;
          const isAt = idx === currentIdx && appState.tripPhase === TripPhase.DOCKING;

          return (
            <div key={checkpoint.id} className="relative z-10">
              <div className="flex items-center gap-4">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center border-4 transition-all duration-500 ${
                  isPassed ? 'bg-blue-500 border-blue-100 text-white' : 
                  isHeadingTo ? 'bg-white border-blue-400 text-blue-400 scale-110' :
                  'bg-white border-slate-200 text-slate-300'
                }`}>
                  {isPassed ? <CheckCircle2 className="w-5 h-5" /> : idx + 1}
                </div>
                <div>
                  <h4 className={`font-bold transition-all ${isAt || isHeadingTo ? 'text-blue-600 text-lg' : 'text-slate-700'}`}>
                    Desa {checkpoint.name}
                  </h4>
                  {isAt && <span className="text-[10px] bg-blue-100 text-blue-700 font-bold px-2 py-0.5 rounded uppercase">Kapal Sedang Bersandar</span>}
                  {isHeadingTo && <span className="text-[10px] bg-orange-100 text-orange-700 font-bold px-2 py-0.5 rounded uppercase">Kapal Menuju Sini</span>}
                </div>
              </div>

              {idx < CHECKPOINTS.length - 1 && (
                <div className="ml-14 mt-4 mb-2 p-2 bg-slate-50 rounded-lg border border-dashed border-slate-200 flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <span className="text-xs font-medium text-slate-500">{ROUTE_SEGMENTS[idx]?.distanceKm} Km</span>
                    <ChevronRight className="w-3 h-3 text-slate-300" />
                    <span className="text-xs font-medium text-slate-500">±{ROUTE_SEGMENTS[idx]?.standardTimeMinutes} menit</span>
                  </div>
                  <div className="h-[2px] flex-1 mx-4 bg-slate-200 relative">
                     {idx === currentIdx && appState.tripPhase === TripPhase.IN_TRANSIT && (
                        <div className="absolute top-1/2 -translate-y-1/2 left-0 w-full">
                           <Ship className="w-4 h-4 text-blue-500 animate-[bounce_1s_infinite] absolute -top-4 left-1/2" />
                        </div>
                     )}
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

// --- Captain Screen Components ---

const CaptainPanel: React.FC<{ 
  appState: AppState; 
  updateState: (partial: Partial<AppState>) => void;
  addLog: (action: string) => void;
}> = ({ appState, updateState, addLog }) => {

  const handleStartTrip = () => {
    updateState({
      currentStatus: ShipStatus.OPERATING,
      tripPhase: TripPhase.IN_TRANSIT,
      currentCheckpointId: null,
      nextCheckpointId: 'v1'
    });
    addLog('Memulai Keberangkatan: Menuju Wandaeha');
  };

  const handleArriveAtCheckpoint = (checkpointId: string) => {
    const cp = CHECKPOINTS.find(c => c.id === checkpointId);
    if (!cp) return;

    const isLast = cp.order === CHECKPOINTS.length - 1;
    const nextCp = CHECKPOINTS.find(c => c.order === cp.order + 1);

    if (isLast) {
      updateState({
        tripPhase: TripPhase.COMPLETED,
        currentCheckpointId: checkpointId,
        nextCheckpointId: null
      });
      addLog(`Tiba di ${cp.name}: Perjalanan Selesai`);
    } else {
      updateState({
        tripPhase: TripPhase.DOCKING,
        currentCheckpointId: checkpointId,
        nextCheckpointId: nextCp?.id || null
      });
      addLog(`Tiba di ${cp.name}`);
    }
  };

  const handleContinueToNext = () => {
    if (!appState.nextCheckpointId) return;
    const nextCp = CHECKPOINTS.find(c => c.id === appState.nextCheckpointId);
    updateState({
      tripPhase: TripPhase.IN_TRANSIT
    });
    addLog(`Melanjutkan perjalanan menuju ${nextCp?.name}`);
  };

  return (
    <div className="p-4 max-w-lg mx-auto pb-24">
      <div className="bg-orange-600 p-6 rounded-2xl text-white mb-6 shadow-xl">
        <div className="flex items-center gap-3 mb-2">
          <Anchor className="w-6 h-6" />
          <h2 className="text-xl font-bold">Panel Kapten</h2>
        </div>
        <p className="opacity-80 text-sm">Operator: Kapt. Herman Syah • {appState.shipName}</p>
        <div className="mt-4 bg-black/10 p-3 rounded-xl border border-white/10">
          <p className="text-xs uppercase font-bold tracking-widest opacity-60">Status Perjalanan Saat Ini:</p>
          <p className="text-lg font-black">{appState.tripPhase}</p>
        </div>
      </div>

      <div className="space-y-6">
        {/* ACTION BUTTONS */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <label className="block text-sm font-bold text-slate-700 mb-4">Kontrol Keberangkatan & Checkpoint:</label>

          {appState.tripPhase === TripPhase.NOT_STARTED && (
            <button
              onClick={handleStartTrip}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-6 rounded-2xl shadow-lg transition-all flex flex-col items-center gap-2 group"
            >
              <div className="bg-white/20 p-2 rounded-full group-hover:scale-110 transition">
                <Play className="w-8 h-8 fill-current" />
              </div>
              <span>MULAI KEBERANGKATAN</span>
              <span className="text-xs font-medium opacity-70">Menuju Checkpoint 1: Wandaeha</span>
            </button>
          )}

          {appState.tripPhase === TripPhase.IN_TRANSIT && appState.nextCheckpointId && (
            <button
              onClick={() => handleArriveAtCheckpoint(appState.nextCheckpointId!)}
              className="w-full bg-green-600 hover:bg-green-700 text-white font-black py-6 rounded-2xl shadow-lg transition-all flex flex-col items-center gap-2 group"
            >
              <div className="bg-white/20 p-2 rounded-full group-hover:scale-110 transition">
                <MapPin className="w-8 h-8" />
              </div>
              <span>TIBA DI {CHECKPOINTS.find(c => c.id === appState.nextCheckpointId)?.name.toUpperCase()}</span>
              <span className="text-xs font-medium opacity-70">Klik jika kapal sudah bersandar</span>
            </button>
          )}

          {appState.tripPhase === TripPhase.DOCKING && appState.nextCheckpointId && (
            <button
              onClick={handleContinueToNext}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-6 rounded-2xl shadow-lg transition-all flex flex-col items-center gap-2 group"
            >
              <div className="bg-white/20 p-2 rounded-full group-hover:scale-110 transition">
                <Navigation className="w-8 h-8" />
              </div>
              <span>LANJUT KE {CHECKPOINTS.find(c => c.id === appState.nextCheckpointId)?.name.toUpperCase()}</span>
              <span className="text-xs font-medium opacity-70">Kapal meninggalkan dermaga</span>
            </button>
          )}

          {appState.tripPhase === TripPhase.COMPLETED && (
            <div className="bg-slate-50 p-6 rounded-2xl text-center border-2 border-dashed border-slate-200">
               <CheckCircle2 className="w-12 h-12 text-slate-400 mx-auto mb-2" />
               <p className="font-bold text-slate-500">Perjalanan Hari Ini Selesai</p>
               <button 
                onClick={() => updateState(INITIAL_APP_STATE)}
                className="mt-4 text-blue-600 text-sm font-bold underline"
               >
                 Reset untuk Trip Baru
               </button>
            </div>
          )}
        </div>

        {/* STATUS OPERASI */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <label className="block text-sm font-bold text-slate-700 mb-3">Update Status Umum:</label>
