              onChange={(e) => updateState({ currentWeather: e.target.value as WeatherStatus })}
              className="w-full text-xs font-bold bg-slate-50 p-2 rounded-lg border outline-none"
            >
              {Object.values(WeatherStatus).map(w => <option key={w} value={w}>{w}</option>)}
            </select>
          </div>
          <div className="bg-white p-4 rounded-2xl border shadow-sm">
            <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Muatan:</label>
            <select 
              value={appState.currentLoad}
              onChange={(e) => updateState({ currentLoad: e.target.value as LoadStatus })}
              className="w-full text-xs font-bold bg-slate-50 p-2 rounded-lg border outline-none"
            >
              {Object.values(LoadStatus).map(l => <option key={l} value={l}>{l}</option>)}
            </select>
          </div>
        </div>

        {/* Delay Info */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <div className="flex justify-between items-center mb-3">
            <label className="text-sm font-bold text-slate-700">Info Delay:</label>
            <span className="text-[10px] bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded font-bold">{appState.delayMinutes} Menit</span>
          </div>
          <input 
            type="range"
            min="0"
            max="120"
            step="5"
            value={appState.delayMinutes}
            onChange={(e) => updateState({ delayMinutes: parseInt(e.target.value) })}
            className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-yellow-500 mb-4"
          />
          <input 
            type="text"
            value={appState.delayReason}
