                  <div className="flex items-center gap-2">
                    <span className="text-xs font-medium text-slate-500">{ROUTE_SEGMENTS[idx]?.distanceKm} Km</span>
                    <ChevronRight className="w-3 h-3 text-slate-300" />
                    <span className="text-xs font-medium text-slate-500">±{ROUTE_SEGMENTS[idx]?.standardTimeMinutes} menit</span>
                  </div>
                  <div className="h-[2px] flex-1 mx-4 bg-slate-200 relative">
                     {idx === currentIdx && appState.tripPhase === TripPhase.IN_TRANSIT && (
                        <div className="absolute top-1/2 -translate-y-1/2 left-0 w-full">
                           <Ship className="w-4 h-4 text-blue-500 animate-[bounce_1s_infinite] absolute -top-4 left-1/2" />
                        </div>
                     )}
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

