const CaptainPanel: React.FC<{ 
  appState: AppState; 
  updateState: (partial: Partial<AppState>) => void;
  addLog: (action: string) => void;
}> = ({ appState, updateState, addLog }) => {
  const [showCancellationForm, setShowCancellationForm] = useState(false);
  const [tempReason, setTempReason] = useState(appState.cancellationReason);
  const [tempDetails, setTempDetails] = useState(appState.cancellationDetails);
  const [error, setError] = useState('');

  const handleStartTrip = () => {
    updateState({
      currentStatus: ShipStatus.OPERATING,
      tripPhase: TripPhase.IN_TRANSIT,
      currentCheckpointId: null,
      nextCheckpointId: 'v1',
      cancellationReason: '',
      cancellationDetails: ''
    });
    addLog('Memulai Keberangkatan: Menuju Wandaeha');
  };

  const handleArriveAtCheckpoint = (checkpointId: string) => {
    const cp = CHECKPOINTS.find(c => c.id === checkpointId);
    if (!cp) return;

    const isLast = cp.order === CHECKPOINTS.length - 1;
    const nextCp = CHECKPOINTS.find(c => c.order === cp.order + 1);

    if (isLast) {
      updateState({
        tripPhase: TripPhase.COMPLETED,
        currentCheckpointId: checkpointId,
        nextCheckpointId: null
      });
      addLog(`Tiba di ${cp.name}: Perjalanan Selesai`);
    } else {
      updateState({
        tripPhase: TripPhase.DOCKING,
        currentCheckpointId: checkpointId,
        nextCheckpointId: nextCp?.id || null
      });
      addLog(`Tiba di ${cp.name}`);
    }
  };

  const handleContinueToNext = () => {
    if (!appState.nextCheckpointId) return;
    const nextCp = CHECKPOINTS.find(c => c.id === appState.nextCheckpointId);
    updateState({
      tripPhase: TripPhase.IN_TRANSIT
    });
    addLog(`Melanjutkan perjalanan menuju ${nextCp?.name}`);
  };

  const confirmCancellation = () => {
    if (!tempReason) {
      setError('Harap pilih alasan pembatalan!');
      return;
    }
    updateState({
      currentStatus: ShipStatus.CANCELLED,
      cancellationReason: tempReason,
      cancellationDetails: tempDetails,
      tripPhase: TripPhase.NOT_STARTED
    });
    addLog(`KEBERANGKATAN DIBATALKAN: ${tempReason}`);
    setShowCancellationForm(false);
    setError('');
  };

  const handleStatusChange = (st: ShipStatus) => {
    if (st === ShipStatus.CANCELLED) {
      setShowCancellationForm(true);
    } else {
      updateState({ 
        currentStatus: st,
        cancellationReason: '',
        cancellationDetails: '' 
      });
      addLog(`Update status ke ${st}`);
      setShowCancellationForm(false);
    }
  };

  return (
    <div className="p-4 max-w-lg mx-auto pb-24">
      <div className={`p-6 rounded-2xl text-white mb-6 shadow-xl transition-colors duration-500 ${appState.currentStatus === ShipStatus.CANCELLED ? 'bg-red-700' : 'bg-orange-600'}`}>
        <div className="flex items-center gap-3 mb-2">
          {appState.currentStatus === ShipStatus.CANCELLED ? <XCircle className="w-6 h-6" /> : <Anchor className="w-6 h-6" />}
          <h2 className="text-xl font-bold">Panel Kapten</h2>
        </div>
        <p className="opacity-80 text-sm">Operator: Kapt. Herman Syah • {appState.shipName}</p>
        <div className="mt-4 bg-black/10 p-3 rounded-xl border border-white/10">
          <p className="text-xs uppercase font-bold tracking-widest opacity-60">Status Perjalanan Saat Ini:</p>
          <p className="text-lg font-black">{appState.currentStatus === ShipStatus.CANCELLED ? 'KEBERANGKATAN DIBATALKAN' : appState.tripPhase}</p>
        </div>
      </div>

      <div className="space-y-6">
        {/* STATUS OPERASI - HIGHLIGHTED BUTTONS */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <label className="block text-sm font-bold text-slate-700 mb-3">Update Status Umum:</label>
          <div className="flex gap-2">
            {[ShipStatus.OPERATING, ShipStatus.DELAYED, ShipStatus.CANCELLED].map((st) => (
              <button
                key={st}
                onClick={() => handleStatusChange(st)}
                className={`flex-1 p-3 rounded-xl text-[10px] font-bold transition border-2 ${
                  appState.currentStatus === st
                    ? st === ShipStatus.OPERATING ? 'bg-green-100 border-green-500 text-green-700' :
                      st === ShipStatus.DELAYED ? 'bg-yellow-100 border-yellow-500 text-yellow-700' :
                      'bg-red-100 border-red-500 text-red-700'
                    : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'
                }`}
              >
                {st}
              </button>
            ))}
          </div>
        </div>

        {/* Cancellation Form Modal/Section */}
        {showCancellationForm && (
          <div className="bg-red-50 border-2 border-red-200 p-6 rounded-2xl shadow-inner animate-in fade-in slide-in-from-top-4">
            <div className="flex items-center gap-2 mb-4 text-red-700">
              <AlertTriangle className="w-6 h-6" />
              <h3 className="font-black text-lg">Konfirmasi Pembatalan</h3>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-red-600 mb-2 uppercase">Pilih Alasan Utama (Wajib):</label>
                <select 
                  value={tempReason}
                  onChange={(e) => { setTempReason(e.target.value); setError(''); }}
                  className="w-full bg-white border border-red-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-red-500 outline-none"
                >
                  <option value="">-- Pilih Alasan --</option>
                  {CANCELLATION_REASONS.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              <div>
                <label className="block text-xs font-bold text-red-600 mb-2 uppercase">Keterangan Tambahan (Opsional):</label>
                <textarea 
                  value={tempDetails}
                  onChange={(e) => setTempDetails(e.target.value)}
                  placeholder="Masukkan detail kerusakan atau informasi lain..."
                  className="w-full bg-white border border-red-200 rounded-xl p-3 text-sm h-20 outline-none focus:ring-2 focus:ring-red-500"
                />
              </div>

              {error && (
                <div className="bg-red-500 text-white text-[10px] font-bold py-1 px-3 rounded-full flex items-center gap-2">
                  <AlertCircle className="w-3 h-3" /> {error}
                </div>
              )}

              <div className="flex gap-2">
                <button 
                  onClick={confirmCancellation}
                  className="flex-1 bg-red-600 text-white font-black py-4 rounded-xl shadow-lg hover:bg-red-700 transition"
                >
                  PUBLIKASIKAN BATAL
                </button>
                <button 
                  onClick={() => { setShowCancellationForm(false); setTempReason(''); setTempDetails(''); }}
                  className="px-6 bg-slate-200 text-slate-600 font-bold py-4 rounded-xl hover:bg-slate-300 transition"
                >
                  Batal
                </button>
              </div>
            </div>
          </div>
        )}

        {/* ACTION BUTTONS (Hidden if status is cancelled) */}
        {appState.currentStatus !== ShipStatus.CANCELLED && (
          <div className="bg-white p-5 rounded-2xl border shadow-sm">
            <label className="block text-sm font-bold text-slate-700 mb-4">Kontrol Keberangkatan & Checkpoint:</label>

            {appState.tripPhase === TripPhase.NOT_STARTED && (
              <button
                onClick={handleStartTrip}
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-6 rounded-2xl shadow-lg transition-all flex flex-col items-center gap-2 group"
              >
                <div className="bg-white/20 p-2 rounded-full group-hover:scale-110 transition">
                  <Play className="w-8 h-8 fill-current" />
                </div>
                <span>MULAI KEBERANGKATAN</span>
                <span className="text-xs font-medium opacity-70">Menuju Checkpoint 1: Wandaeha</span>
              </button>
            )}

            {appState.tripPhase === TripPhase.IN_TRANSIT && appState.nextCheckpointId && (
              <button
                onClick={() => handleArriveAtCheckpoint(appState.nextCheckpointId!)}
                className="w-full bg-green-600 hover:bg-green-700 text-white font-black py-6 rounded-2xl shadow-lg transition-all flex flex-col items-center gap-2 group"
              >
                <div className="bg-white/20 p-2 rounded-full group-hover:scale-110 transition">
                  <MapPin className="w-8 h-8" />
                </div>
                <span>TIBA DI {CHECKPOINTS.find(c => c.id === appState.nextCheckpointId)?.name.toUpperCase()}</span>
                <span className="text-xs font-medium opacity-70">Klik jika kapal sudah bersandar</span>
              </button>
            )}

            {appState.tripPhase === TripPhase.DOCKING && appState.nextCheckpointId && (
              <button
                onClick={handleContinueToNext}
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-6 rounded-2xl shadow-lg transition-all flex flex-col items-center gap-2 group"
              >
                <div className="bg-white/20 p-2 rounded-full group-hover:scale-110 transition">
                  <Navigation className="w-8 h-8" />
                </div>
                <span>LANJUT KE {CHECKPOINTS.find(c => c.id === appState.nextCheckpointId)?.name.toUpperCase()}</span>
                <span className="text-xs font-medium opacity-70">Kapal meninggalkan dermaga</span>
              </button>
            )}

            {appState.tripPhase === TripPhase.COMPLETED && (
              <div className="bg-slate-50 p-6 rounded-2xl text-center border-2 border-dashed border-slate-200">
                 <CheckCircle2 className="w-12 h-12 text-slate-400 mx-auto mb-2" />
                 <p className="font-bold text-slate-500">Perjalanan Hari Ini Selesai</p>
                 <button 
                  onClick={() => updateState(INITIAL_APP_STATE)}
                  className="mt-4 text-blue-600 text-sm font-bold underline"
                 >
                   Reset untuk Trip Baru
                 </button>
              </div>
            )}
          </div>
        )}

        {/* Cuaca & Muatan Grid (Hidden if status is cancelled) */}
        {appState.currentStatus !== ShipStatus.CANCELLED && (
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-white p-4 rounded-2xl border shadow-sm">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Cuaca:</label>
              <select 
                value={appState.currentWeather}
                onChange={(e) => updateState({ currentWeather: e.target.value as WeatherStatus })}
                className="w-full text-xs font-bold bg-slate-50 p-2 rounded-lg border outline-none"
              >
                {Object.values(WeatherStatus).map(w => <option key={w} value={w}>{w}</option>)}
              </select>
            </div>
            <div className="bg-white p-4 rounded-2xl border shadow-sm">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Muatan:</label>
              <select 
                value={appState.currentLoad}
                onChange={(e) => updateState({ currentLoad: e.target.value as LoadStatus })}
                className="w-full text-xs font-bold bg-slate-50 p-2 rounded-lg border outline-none"
              >
                {Object.values(LoadStatus).map(l => <option key={l} value={l}>{l}</option>)}
              </select>
            </div>
          </div>
        )}

        {/* Delay Info (Hidden if status is cancelled) */}
        {appState.currentStatus !== ShipStatus.CANCELLED && (
          <div className="bg-white p-5 rounded-2xl border shadow-sm">
            <div className="flex justify-between items-center mb-3">
              <label className="text-sm font-bold text-slate-700">Info Delay:</label>
              <span className="text-[10px] bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded font-bold">{appState.delayMinutes} Menit</span>
            </div>
            <input 
              type="range"
              min="0"
              max="120"
              step="5"
              value={appState.delayMinutes}
              onChange={(e) => updateState({ delayMinutes: parseInt(e.target.value) })}
              className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-yellow-500 mb-4"
            />
            <input 
              type="text"
              value={appState.delayReason}
              onChange={(e) => updateState({ delayReason: e.target.value })}
              placeholder="Alasan delay..."
              className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-yellow-500 outline-none"
            />
          </div>
        )}
      </div>
    </div>
  );
};

