// --- Main App Entry ---

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>('PUBLIC');
  const [appState, setAppState] = useState<AppState>(INITIAL_APP_STATE);
  const [targetId, setTargetId] = useState<string>('v5');
  const [logs, setLogs] = useState<ActivityLog[]>([]);

  const updateState = (partial: Partial<AppState>) => {
    setAppState(prev => ({ ...prev, ...partial }));
  };

  const addLog = (action: string) => {
    const newLog: ActivityLog = {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString('id-ID'),
      action,
      user: role === 'CAPTAIN' ? 'Kapt. Herman' : 'Superadmin'
    };
    setLogs(prev => [...prev, newLog]);
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50">
      <RunningText text={appState.announcement} appState={appState} />
      <Navbar role={role} setRole={setRole} />

      <main className="container mx-auto px-4 py-6">
        {role === 'PUBLIC' && (
          <div className="max-w-2xl mx-auto space-y-6">
            <StatusIndicator appState={appState} />

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <SmartETACard appState={appState} targetId={targetId} setTargetId={setTargetId} />

              <div className={`bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-center ${appState.currentStatus === ShipStatus.CANCELLED ? 'opacity-50 grayscale' : ''}`}>
                <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
                  <Clock className="w-5 h-5 text-orange-500" /> Ringkasan Jadwal
                </h3>
                <div className="space-y-4">
                  <div className="flex justify-between border-b pb-2">
                    <span className="text-slate-500 text-sm">Nama Kapal</span>
                    <span className="font-bold text-slate-800 text-sm">{appState.shipName}</span>
                  </div>
                  <div className="flex justify-between border-b pb-2">
                    <span className="text-slate-500 text-sm">Jam Berangkat</span>
                    <span className="font-bold text-slate-800 text-sm">{appState.departureTime}</span>
                  </div>
                  <div className="flex justify-between border-b pb-2">
                    <span className="text-slate-500 text-sm">Rute Utama</span>
                    <span className="font-bold text-slate-800 text-sm">Laonti - Kendari</span>
                  </div>
                </div>
                {appState.delayMinutes > 0 && appState.currentStatus !== ShipStatus.CANCELLED && (
                  <div className="mt-6 p-4 bg-orange-50 rounded-xl flex items-start gap-3 border border-orange-100">
                    <AlertCircle className="w-5 h-5 text-orange-500 shrink-0 mt-0.5" />
                    <p className="text-xs text-orange-800 leading-relaxed font-medium">
                      Perhatian: Keberangkatan tertunda karena {appState.delayReason || 'alasan teknis'}.
                    </p>
                  </div>
                )}
                {appState.currentStatus === ShipStatus.CANCELLED && (
                  <div className="mt-6 p-4 bg-red-50 rounded-xl flex items-start gap-3 border border-red-100">
                    <XCircle className="w-5 h-5 text-red-500 shrink-0 mt-0.5" />
                    <p className="text-xs text-red-800 leading-relaxed font-black uppercase">
                      JADWAL DIBATALKAN
                    </p>
                  </div>
                )}
              </div>
            </div>

            <RouteTimeline appState={appState} />

            <div className="text-center pb-8 opacity-40">
              <p className="text-xs font-bold uppercase tracking-widest text-slate-400">Hubungi Kami: 0812-XXXX-XXXX (Pelabuhan Laonti)</p>
            </div>
          </div>
        )}

        {role === 'CAPTAIN' && (
          <CaptainPanel appState={appState} updateState={updateState} addLog={addLog} />
        )}

        {role === 'ADMIN' && (
          <AdminPanel appState={appState} updateState={updateState} logs={logs} />
        )}
      </main>

      {/* Floating Role Label */}
      <div className="fixed bottom-4 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur shadow-2xl border rounded-full px-6 py-2 z-50 flex items-center gap-3">
        <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Mode:</span>
        <span className={`text-xs font-bold px-3 py-1 rounded-full ${
          role === 'PUBLIC' ? 'bg-blue-100 text-blue-700' :
          role === 'CAPTAIN' ? 'bg-orange-100 text-orange-700' :
          'bg-slate-800 text-white'
        }`}>
          {role}
        </span>
      </div>
    </div>
  );
};

export default App;

export enum ShipStatus {
  OPERATING = 'BEROPERASI',
  CANCELLED = 'TIDAK BEROPERASI',
  DELAYED = 'TERTUNDA'
}

export enum WeatherStatus {
  SUNNY = 'Cerah',
  RAIN = 'Hujan',
  ROUGH_WAVES = 'Berombak Besar'
}

export enum LoadStatus {
  AVAILABLE = 'Muatan Masih Tersedia',
  FULL = 'PENUH'
}

export enum TripPhase {
  NOT_STARTED = 'Belum Berangkat',
  IN_TRANSIT = 'Dalam Perjalanan',
  DOCKING = 'Sedang Bersandar',
  COMPLETED = 'Perjalanan Selesai'
}

export interface Checkpoint {
  id: string;
  name: string;
  order: number;
}

export interface RouteSegment {
  fromId: string;
  toId: string;
  distanceKm: number;
  standardTimeMinutes: number;
}

export interface PassengerRecord {
  id: string;
  name: string;
  villageId: string;
  timestamp: string;
}

export interface UserProfile {
  id: string;
  name: string;
  role: UserRole;
  isLoggedIn: boolean;
}

export interface AppState {
  currentStatus: ShipStatus;
  tripPhase: TripPhase;
  currentCheckpointId: string | null;
  nextCheckpointId: string | null;
  currentWeather: WeatherStatus;
  currentLoad: LoadStatus;
  delayReason: string;
  delayMinutes: number;
  announcement: string;
  shipName: string;
  departureTime: string;
  cancellationReason: string;
  cancellationDetails: string;
  registeredPassengers: PassengerRecord[];
}

export type UserRole = 'PUBLIC' | 'PASSENGER' | 'CAPTAIN' | 'ADMIN';

export interface ActivityLog {
  id: string;
  timestamp: string;
  action: string;
  user: string;
}

