      return `PENTING: Keberangkatan hari ini DIBATALKAN karena ${appState.cancellationReason}. ${appState.cancellationDetails}`;
    }
    return text;
  }, [text, appState.currentStatus, appState.cancellationReason, appState.cancellationDetails]);

  return (
    <div className={`text-white py-2 overflow-hidden whitespace-nowrap sticky top-0 z-50 shadow-md transition-colors duration-500 ${appState.currentStatus === ShipStatus.CANCELLED ? 'bg-red-700' : 'bg-blue-600'}`}>
      <div className="inline-block animate-scroll font-medium uppercase tracking-wide">
        {displayMessage} • {displayMessage} • {displayMessage}
      </div>
    </div>
  );
};

