const CaptainPanel: React.FC<{ 
  appState: AppState; 
  updateState: (partial: Partial<AppState>) => void;
  addLog: (action: string) => void;
}> = ({ appState, updateState, addLog }) => {
  const [showCancellationForm, setShowCancellationForm] = useState(false);
  const [tempReason, setTempReason] = useState(appState.cancellationReason);
  const [tempDetails, setTempDetails] = useState(appState.cancellationDetails);
  const [error, setError] = useState('');

  const handleStartTrip = () => {
    updateState({
      currentStatus: ShipStatus.OPERATING,
      tripPhase: TripPhase.IN_TRANSIT,
      currentCheckpointId: null,
      nextCheckpointId: 'v1',
      cancellationReason: '',
      cancellationDetails: ''
    });
    addLog('Kapten memulai keberangkatan: Broadcast ke penumpang aktif.');
  };

  const handleArriveAtCheckpoint = (checkpointId: string) => {
    const cp = CHECKPOINTS.find(c => c.id === checkpointId);
    if (!cp) return;
    const isLast = cp.order === CHECKPOINTS.length - 1;
    const nextCp = CHECKPOINTS.find(c => c.order === cp.order + 1);

    if (isLast) {
      updateState({ tripPhase: TripPhase.COMPLETED, currentCheckpointId: checkpointId, nextCheckpointId: null });
      addLog(`Tiba di ${cp.name}: Perjalanan Selesai`);
    } else {
      updateState({ tripPhase: TripPhase.DOCKING, currentCheckpointId: checkpointId, nextCheckpointId: nextCp?.id || null });
      addLog(`Tiba di ${cp.name}`);
    }
  };

  const confirmCancellation = () => {
    if (!tempReason) { setError('Harap pilih alasan pembatalan!'); return; }
    updateState({
      currentStatus: ShipStatus.CANCELLED,
      cancellationReason: tempReason,
      cancellationDetails: tempDetails,
      tripPhase: TripPhase.NOT_STARTED
    });
    addLog(`BROADCAST PEMBATALAN: Menginformasikan ${appState.registeredPassengers.length} penumpang.`);
    setShowCancellationForm(false);
    setError('');
  };

  const handleStatusChange = (st: ShipStatus) => {
    if (st === ShipStatus.CANCELLED) {
      setShowCancellationForm(true);
    } else {
      updateState({ currentStatus: st, cancellationReason: '', cancellationDetails: '' });
      addLog(`Update status ke ${st}`);
      setShowCancellationForm(false);
    }
  };

  return (
    <div className="p-4 max-w-lg mx-auto pb-24">
      <div className={`p-6 rounded-3xl text-white mb-6 shadow-xl transition-colors duration-500 ${appState.currentStatus === ShipStatus.CANCELLED ? 'bg-red-700' : 'bg-orange-600'}`}>
        <div className="flex items-center gap-3 mb-2">
          {appState.currentStatus === ShipStatus.CANCELLED ? <XCircle className="w-6 h-6" /> : <Anchor className="w-6 h-6" />}
          <h2 className="text-xl font-bold">Panel Operasional Kapal</h2>
        </div>
        <p className="opacity-80 text-sm">Operator: Kapt. Herman Syah • {appState.shipName}</p>
        <div className="mt-4 flex gap-4">
           <div className="bg-black/10 px-4 py-2 rounded-2xl border border-white/10 flex-1">
              <p className="text-[10px] uppercase font-bold tracking-widest opacity-60">Fase:</p>
              <p className="text-sm font-black">{appState.tripPhase}</p>
           </div>
           <div className="bg-black/10 px-4 py-2 rounded-2xl border border-white/10">
              <p className="text-[10px] uppercase font-bold tracking-widest opacity-60">Penumpang:</p>
              <p className="text-sm font-black">{appState.registeredPassengers.length} Orang</p>
           </div>
        </div>
      </div>

      <div className="space-y-6">
        {/* ACTION BUTTONS */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <label className="block text-sm font-bold text-slate-700 mb-4">Kontrol Alur Perjalanan:</label>

          {appState.currentStatus !== ShipStatus.CANCELLED && (
            <>
              {appState.tripPhase === TripPhase.NOT_STARTED && (
                <button
                  onClick={handleStartTrip}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-6 rounded-2xl shadow-lg transition-all flex flex-col items-center gap-2 group"
                >
                  <Play className="w-8 h-8 fill-current group-hover:scale-110 transition" />
                  <span>MULAI BERANGKAT</span>
                  <span className="text-xs font-medium opacity-70">Sistem akan broadcast status "BEROPERASI"</span>
                </button>
              )}

              {appState.tripPhase === TripPhase.IN_TRANSIT && appState.nextCheckpointId && (
                <button
                  onClick={() => handleArriveAtCheckpoint(appState.nextCheckpointId!)}
                  className="w-full bg-green-600 hover:bg-green-700 text-white font-black py-6 rounded-2xl shadow-lg transition-all flex flex-col items-center gap-2"
                >
                  <MapPin className="w-8 h-8" />
                  <span>TIBA DI {CHECKPOINTS.find(c => c.id === appState.nextCheckpointId)?.name.toUpperCase()}</span>
                </button>
              )}

              {appState.tripPhase === TripPhase.DOCKING && appState.nextCheckpointId && (
                <button
                  onClick={() => updateState({ tripPhase: TripPhase.IN_TRANSIT })}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-6 rounded-2xl shadow-lg transition-all flex flex-col items-center gap-2"
                >
                  <Navigation className="w-8 h-8" />
                  <span>LANJUT KE {CHECKPOINTS.find(c => c.id === appState.nextCheckpointId)?.name.toUpperCase()}</span>
                </button>
              )}
            </>
          )}

          {appState.currentStatus === ShipStatus.CANCELLED && (
            <div className="p-6 bg-red-50 rounded-2xl border-2 border-dashed border-red-200 text-center">
              <XCircle className="w-12 h-12 text-red-300 mx-auto mb-2" />
              <p className="font-black text-red-800">PERJALANAN DIBATALKAN</p>
              <button 
                onClick={() => updateState(INITIAL_APP_STATE)}
                className="mt-4 text-xs font-bold text-slate-500 underline"
              >
                Reset Untuk Keberangkatan Baru
              </button>
            </div>
          )}
        </div>

        {/* STATUS UPDATE */}
        <div className="bg-white p-5 rounded-2xl border shadow-sm">
          <label className="block text-sm font-bold text-slate-700 mb-3">Update Status Global:</label>
          <div className="flex gap-2">
            {[ShipStatus.OPERATING, ShipStatus.DELAYED, ShipStatus.CANCELLED].map((st) => (
              <button
                key={st}
                onClick={() => handleStatusChange(st)}
                className={`flex-1 p-3 rounded-xl text-[10px] font-bold transition border-2 ${
                  appState.currentStatus === st
                    ? st === ShipStatus.OPERATING ? 'bg-green-100 border-green-500 text-green-700' :
                      st === ShipStatus.DELAYED ? 'bg-yellow-100 border-yellow-500 text-yellow-700' :
                      'bg-red-100 border-red-500 text-red-700'
                    : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'
                }`}
              >
                {st}
              </button>
            ))}
          </div>
        </div>

        {/* Cancellation UI Overlay */}
        {showCancellationForm && (
          <div className="bg-red-50 border-2 border-red-300 p-6 rounded-2xl shadow-inner space-y-4">
             <h3 className="font-black text-red-800 flex items-center gap-2"><AlertTriangle className="w-5 h-5" /> Konfirmasi Broadcast Batal</h3>
             <select 
                value={tempReason}
                onChange={(e) => setTempReason(e.target.value)}
                className="w-full p-3 bg-white border border-red-200 rounded-xl text-sm"
             >
                <option value="">-- Pilih Alasan --</option>
                {CANCELLATION_REASONS.map(r => <option key={r} value={r}>{r}</option>)}
             </select>
             <textarea 
                value={tempDetails}
                onChange={(e) => setTempDetails(e.target.value)}
                placeholder="Penjelasan singkat tambahan..."
                className="w-full p-3 bg-white border border-red-200 rounded-xl text-sm h-20"
             />
             {error && <p className="text-[10px] text-red-600 font-bold">{error}</p>}
             <div className="flex gap-2">
                <button onClick={confirmCancellation} className="flex-1 bg-red-600 text-white font-black py-3 rounded-xl shadow-md">Kirim Notifikasi Pembatalan</button>
                <button onClick={() => setShowCancellationForm(false)} className="px-4 bg-slate-200 text-slate-600 font-bold rounded-xl">Tutup</button>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

