  const handleCheckIn = (villageId: string) => {
    if (!userProfile) return;
    const newRecord: PassengerRecord = {
      id: userProfile.id,
      name: userProfile.name,
      villageId,
      timestamp: new Date().toLocaleTimeString('id-ID')
    };
    updateState({
      registeredPassengers: [...appState.registeredPassengers, newRecord]
    });
    addLog(`${userProfile.name} mendaftar keberangkatan di ${CHECKPOINTS.find(c => c.id === villageId)?.name}`);
  };

  const handleLogout = () => {
    setUserProfile(null);
    setRole('PUBLIC');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50">
      <RunningText text={appState.announcement} appState={appState} />
      <Navbar role={role} setRole={setRole} user={userProfile} onLogout={handleLogout} />

