const StatusIndicator: React.FC<{ appState: AppState }> = ({ appState }) => {
  const getColor = () => {
    if (appState.tripPhase === TripPhase.COMPLETED) return 'bg-slate-700';
    switch (appState.currentStatus) {
      case ShipStatus.OPERATING: return 'bg-green-500';
      case ShipStatus.DELAYED: return 'bg-yellow-500';
      case ShipStatus.CANCELLED: return 'bg-red-500';
    }
  };

  const getSubStatusText = () => {
    if (appState.currentStatus === ShipStatus.CANCELLED) return `ALASAN: ${appState.cancellationReason || 'Tidak disebutkan'}`;
    if (appState.tripPhase === TripPhase.NOT_STARTED) return "Menunggu Keberangkatan";
    if (appState.tripPhase === TripPhase.COMPLETED) return "Tiba di Kendari (Selesai)";
    const nextCp = CHECKPOINTS.find(c => c.id === appState.nextCheckpointId);
    if (appState.tripPhase === TripPhase.IN_TRANSIT) return `Sedang Menuju ${nextCp?.name || 'Tujuan'}`;
    if (appState.tripPhase === TripPhase.DOCKING) return `Tiba di ${CHECKPOINTS.find(c => c.id === appState.currentCheckpointId)?.name || 'Checkpoint'}`;
    return appState.currentStatus;
  };

  return (
    <div className={`${getColor()} p-8 rounded-3xl shadow-lg text-white mb-6 transition-all`}>
      <div className="flex justify-between items-start">
        <div>
          <p className="text-xs font-bold opacity-80 uppercase tracking-widest mb-1">Status Kapal</p>
          <h2 className="text-4xl font-black mb-2 tracking-tight">{appState.currentStatus}</h2>
          <p className="text-lg font-bold opacity-90 flex items-center gap-2">
            {appState.currentStatus === ShipStatus.CANCELLED ? <XCircle className="w-5 h-5" /> : <Navigation className="w-5 h-5" />}
            {getSubStatusText()}
          </p>
        </div>
        <div className="bg-white/20 p-4 rounded-2xl backdrop-blur-md">
          {appState.currentStatus === ShipStatus.CANCELLED ? (
            <XCircle className="w-12 h-12" />
          ) : (
            <Ship className={`w-12 h-12 ${appState.tripPhase === TripPhase.IN_TRANSIT ? 'animate-pulse' : ''}`} />
          )}
        </div>
      </div>
    </div>
  );
};

